 27→@Suppress("MagicNumber", "TooManyFunctions")
 28→internal class DrawerViewModel(
 29→    private val getDrawerConfig: UseCase.GetDrawerConfig,
 30→    private val saveDrawerConfig: UseCase.SaveDrawerConfig,
 31→    private val getDisplayAccounts: UseCase.GetDisplayAccounts,
 32→    private val getDisplayFoldersForAccount: UseCase.GetDisplayFoldersForAccount,
 33→    private val syncAccount: UseCase.SyncAccount,
 34→    private val syncAllAccounts: UseCase.SyncAllAccounts,
 35→    initialState: State = State(),
 36→) : BaseViewModel<State, Event, Effect>(
 37→    initialState = initialState,
 38→),
 39→    ViewModel {
 40→
 41→    init {
 42→        viewModelScope.launch {
 43→            getDrawerConfig().collectLatest { config ->
 44→                updateState {
 45→                    it.copy(config = config)
 46→                }
 47→            }
 48→        }
 49→
 50→        viewModelScope.launch {
 51→            loadAccounts()
 52→        }
 53→
 54→        viewModelScope.launch {
 55→            loadFolders()
 56→        }
 57→    }
 58→
 59→    private suspend fun loadAccounts() {
 60→        getDisplayAccounts().collectLatest { accounts ->
 61→            updateAccounts(accounts)
 62→        }
 63→    }
 64→
 65→    private fun updateAccounts(accounts: List<DisplayAccount>) {
 66→        val selectedAccount = accounts.find { it.id == state.value.selectedAccountId }
 67→            ?: accounts.firstOrNull()
 68→
 69→        updateState {
 70→            it.copy(
 71→                accounts = accounts.toImmutableList(),
 72→                selectedAccountId = selectedAccount?.id,
 73→            )
 74→        }
 75→    }
 76→
 77→    @OptIn(ExperimentalCoroutinesApi::class)
 78→    private suspend fun loadFolders() {
 79→        state.map {
 80→            it.selectedAccountId?.let { accountId ->
 81→                Pair(accountId, it.config.showUnifiedFolders)
 82→            }
 83→        }.filterNotNull()
 84→            .distinctUntilChanged()
 85→            .flatMapLatest { (accountId, showUnifiedInbox) ->
 86→                getDisplayFoldersForAccount(accountId, showUnifiedInbox)
 87→            }.collect { folders ->
 88→                updateFolders(folders)
 89→            }
 90→    }
 91→
 92→    private fun updateFolders(displayFolders: List<DisplayFolder>) {
 93→        val selectedFolder = displayFolders.find {
 94→            it.id == state.value.selectedFolderId
 95→        } ?: displayFolders.firstOrNull()
 96→
 97→        updateState {
 98→            it.copy(
 99→                folders = displayFolders.toImmutableList(),
100→                selectedFolderId = selectedFolder?.id,
101→            )
102→        }
103→    }
104→
105→    override fun event(event: Event) {
106→        when (event) {
107→            is Event.SelectAccount -> selectAccount(event.accountId)
108→            is Event.SelectFolder -> selectFolder(event.folderId)
109→
110→            is Event.OnAccountClick -> openAccount(event.account)
111→            is Event.OnFolderClick -> openFolder(event.folder)
112→            is Event.OnAccountViewClick -> {
113→                openAccount(
114→                    state.value.accounts.nextOrFirst(event.account),
115→                )
116→            }
117→
118→            Event.OnAccountSelectorClick -> {
119→                saveDrawerConfig(
120→                    state.value.config.copy(showAccountSelector = state.value.config.showAccountSelector.not()),
121→                ).launchIn(viewModelScope)
122→            }
123→            Event.OnManageFoldersClick -> emitEffect(Effect.OpenManageFolders)
124→            Event.OnSettingsClick -> emitEffect(Effect.OpenSettings)
125→            Event.OnSyncAccount -> onSyncAccount()
126→            Event.OnSyncAllAccounts -> onSyncAllAccounts()
127→        }
128→    }
129→
130→    private fun selectAccount(accountId: String?) {
131→        updateState {
132→            it.copy(
133→                selectedAccountId = accountId,
134→            )
135→        }
136→    }
137→
138→    private fun selectFolder(folderId: String?) {
139→        updateState {
140→            it.copy(
141→                selectedFolderId = folderId,
142→            )
143→        }
144→    }
145→
146→    private fun openAccount(account: DisplayAccount?) {
147→        if (account != null) {
148→            emitEffect(Effect.OpenAccount(account.id))
149→        }
150→    }
151→
152→    private fun ImmutableList<DisplayAccount>.nextOrFirst(account: DisplayAccount): DisplayAccount? {
153→        val index = indexOf(account)
154→        return if (index == -1) {
155→            null
156→        } else if (index == size - 1) {
157→            get(0)
158→        } else {
159→            get(index + 1)
160→        }
161→    }
162→
163→    private fun openFolder(folder: DisplayFolder) {
164→        if (folder is DisplayAccountFolder) {
165→            emitEffect(Effect.OpenFolder(folder.folder.id))
166→        } else if (folder is DisplayUnifiedFolder) {
167→            emitEffect(Effect.OpenUnifiedFolder)
168→        }
169→
170→        viewModelScope.launch {
171→            delay(DRAWER_CLOSE_DELAY)
172→            emitEffect(Effect.CloseDrawer)
173→        }
174→    }
175→
176→    private fun onSyncAccount() {
177→        if (state.value.isLoading || state.value.selectedAccountId == null) return
178→
179→        viewModelScope.launch {
180→            updateState {
181→                it.copy(isLoading = true)
182→            }
183→
184→            state.value.selectedAccountId?.let { syncAccount(it).collect() }
185→
186→            updateState {
187→                it.copy(isLoading = false)
188→            }
189→        }
190→    }
191→
192→    private fun onSyncAllAccounts() {
193→        if (state.value.isLoading) return
194→
195→        viewModelScope.launch {
196→            updateState {
197→                it.copy(isLoading = true)
198→            }
199→
200→            syncAllAccounts().collect()
201→
202→            updateState {
203→                it.copy(isLoading = false)
204→            }
205→        }
206→    }
207→}
208→
209→/**
210→ * Delay before closing the drawer to avoid the drawer being closed immediately and give time
211→ * for the ripple effect to finish.
212→ */
213→private const val DRAWER_CLOSE_DELAY = 250L
